import Cookies from 'js-cookie'
import axios from 'axios';

function StudentCookie() {
            axios.post('http://localhost:80/api/getStudents.php', Cookies.get('studentID'))
            .then((response) => {
                if(response.data) {
                    Cookies.set('userInfo', response.data[0].firstName + ' ' + response.data[0].lastName)
                }
                
            })
            .catch(error => {
                console.log(error);
            })
}

export default StudentCookie
